import type { Metadata } from "next";
import Shipping from "./Shipping";

export const metadata: Metadata = {
  title: "出荷検品 / 梱包 | ぐんじょう WMS",
  description:
    "出荷検品・梱包（出荷ピッキング後の出荷確定工程）の画面。出荷番号 / 受注番号で出荷を呼び出し、配送先 / 出荷予定日 / 配送便 / 担当者 / ステータス（未検品 / 検品・梱包中 / 梱包完了 / 出荷済）を表示。検品・梱包明細（商品名 / SKU・JAN / 受注数量 / 梱包済数量 / 割当カートン / 状態）に対し、2段スキャン（① カートン（梱包箱）をスキャンして開く ② 商品の JAN/SKU をスキャンして開いているカートンへ1点ずつ梱包、受注に無い商品はエラー読み上げ、カートン未オープン時は先にカートンをスキャンと案内）で梱包。複数カートン管理（中身・サイズ・重量）、最終検品チェックリスト（数量一致・外装/品質・同梱物）、配送ラベル / 送り状（配送業者・追跡番号・お届け希望日時）、出荷確定ゲート（全行梱包完了または保留理由付き・全カートン計量・配送業者選択・検品完了までブロック）、出荷サマリ（カートン × 重量 × 追跡番号）を備えたハンディ端末向けツールです。",
};

export default function ShippingPage() {
  return <Shipping />;
}

/**
 * Domain model + pure helpers for the 出荷検品 / 梱包 (outbound shipping
 * inspection + packing) screen. Kept framework-free so the component stays
 * presentational and the packing logic is unit-testable.
 *
 * The flow: shipment → open a carton (scan) → scan items into that carton
 * (+1 each, can't over-pack) → final inspection checklist → weigh + label →
 * choose carrier + tracking → dispatch.
 */

export type CarrierCode = "yamato" | "sagawa" | "japanpost";

export interface Carrier {
  code: CarrierCode;
  label: string;
  /** Tracking-number format hint shown under the field. */
  hint: string;
}

export const CARRIERS: Carrier[] = [
  { code: "yamato", label: "ヤマト運輸", hint: "12桁（例 4912-3456-7890）" },
  { code: "sagawa", label: "佐川急便", hint: "12桁の問い合わせ番号" },
  { code: "japanpost", label: "日本郵便", hint: "追跡番号（例 1234-5678-9012）" },
];

export const CARRIER_LABEL: Record<CarrierCode, string> = {
  yamato: "ヤマト運輸",
  sagawa: "佐川急便",
  japanpost: "日本郵便",
};

/** JIS-style size codes used by Japanese parcel carriers. */
export type SizeCode = "60" | "80" | "100" | "120" | "140" | "160";
export const SIZE_CODES: SizeCode[] = ["60", "80", "100", "120", "140", "160"];

/** Reason a line ships short (backorder / hold) instead of fully packed. */
export type HoldReason = "backorder" | "damaged" | "out_of_stock" | "customer_hold";
export const HOLD_REASON_OPTIONS: { value: HoldReason; label: string }[] = [
  { value: "backorder", label: "入荷待ち（次便へ）" },
  { value: "out_of_stock", label: "在庫切れ" },
  { value: "damaged", label: "破損・不良" },
  { value: "customer_hold", label: "客先保留" },
];

/** One line on the shipment to inspect & pack. */
export interface PackLine {
  id: string;
  name: string;
  sku: string;
  jan: string;
  ordered: number;
  /** Scan-driven, also hand-editable. Sum of this item across all cartons. */
  packed: number;
  /** When held short, the line is settled with a reason instead of fully packed. */
  held: boolean;
  reason: HoldReason | "";
}

/** A shipping carton. Items are packed into the *active* (open) carton. */
export interface Carton {
  id: string;
  /** Carton barcode / number (scanned to open). */
  barcode: string;
  size: SizeCode;
  /** Weight in kg, editable. 0 / undefined ⇒ not yet weighed. */
  weight: number;
  /** lineId → count packed into THIS carton. */
  contents: Record<string, number>;
  closed: boolean;
}

export interface Shipment {
  shipmentNo: string;
  orderNo: string;
  shipToName: string;
  shipToAddr: string;
  shipDate: string;
  /** Requested delivery service tier shown on the header. */
  service: string;
  packer: string;
  lines: PackLine[];
}

// ─── line state ────────────────────────────────────────────────────────────────
export type LineState = "pending" | "partial" | "complete" | "held" | "over";

export const LINE_STATE_LABEL: Record<LineState, string> = {
  pending: "未",
  partial: "一部",
  complete: "完了",
  held: "保留",
  over: "過剰",
};

export function lineState(l: PackLine): LineState {
  if (l.held) return "held";
  if (l.packed > l.ordered) return "over";
  if (l.packed === 0) return "pending";
  if (l.packed >= l.ordered) return "complete";
  return "partial";
}

/** Remaining to pack (positive) or over-pack (negative). */
export function lineRemaining(l: PackLine): number {
  return l.ordered - l.packed;
}

/** A line is settled when fully packed OR held with a reason. */
export function lineSettled(l: PackLine): boolean {
  if (l.held) return l.reason !== "";
  return l.packed >= l.ordered && l.packed <= l.ordered;
}

// ─── totals ──────────────────────────────────────────────────────────────────
export const totalOrdered = (lines: PackLine[]) => lines.reduce((s, l) => s + l.ordered, 0);
export const totalPacked = (lines: PackLine[]) => lines.reduce((s, l) => s + l.packed, 0);
export const completedLineCount = (lines: PackLine[]) =>
  lines.filter((l) => lineState(l) === "complete").length;
export const settledLineCount = (lines: PackLine[]) => lines.filter(lineSettled).length;
export const heldLineCount = (lines: PackLine[]) => lines.filter((l) => l.held).length;
export const overLineCount = (lines: PackLine[]) =>
  lines.filter((l) => l.packed > l.ordered).length;

export const cartonItemCount = (c: Carton) =>
  Object.values(c.contents).reduce((s, n) => s + n, 0);
export const totalCartonWeight = (cartons: Carton[]) =>
  cartons.reduce((s, c) => s + (c.weight || 0), 0);
export const unweighedCartonCount = (cartons: Carton[]) =>
  cartons.filter((c) => !c.weight || c.weight <= 0).length;

// ─── lookups & scan matching ───────────────────────────────────────────────────
export function lookupShipment(value: string): Shipment | undefined {
  const v = value.trim().toUpperCase();
  return SHIPMENTS.find(
    (s) => s.shipmentNo.toUpperCase() === v || s.orderNo.toUpperCase() === v,
  );
}

/**
 * Resolve a CARTON-stage scan.
 *  - matches an existing carton barcode → "existing"
 *  - looks like a fresh carton label → "new" (caller creates it)
 */
export type CartonScan =
  | { kind: "existing"; cartonId: string; barcode: string }
  | { kind: "new"; barcode: string };

export function matchCartonScan(cartons: Carton[], code: string): CartonScan {
  const c = code.trim();
  const found = cartons.find((x) => x.barcode.toUpperCase() === c.toUpperCase());
  if (found) return { kind: "existing", cartonId: found.id, barcode: found.barcode };
  return { kind: "new", barcode: c };
}

/**
 * Resolve an ITEM-stage scan against the shipment lines. The guard (a carton
 * must be open) is enforced by the caller before this runs.
 */
export type ItemScan =
  | { kind: "packed"; lineId: string; name: string; packed: number; ordered: number }
  | { kind: "full"; name: string; ordered: number }
  | { kind: "held"; name: string }
  | { kind: "unknown"; code: string };

export function matchItemScan(lines: PackLine[], code: string): ItemScan {
  const c = code.trim();
  const line = lines.find(
    (l) => l.jan === c || l.sku.toUpperCase() === c.toUpperCase(),
  );
  if (!line) return { kind: "unknown", code: c };
  if (line.held) return { kind: "held", name: line.name };
  if (line.packed >= line.ordered)
    return { kind: "full", name: line.name, ordered: line.ordered };
  return {
    kind: "packed",
    lineId: line.id,
    name: line.name,
    packed: line.packed + 1,
    ordered: line.ordered,
  };
}

// ─── dispatch gate ──────────────────────────────────────────────────────────────
export interface DispatchState {
  carrier: CarrierCode | "";
  tracking: string;
  deliverySlot: string;
  /** Inspection checklist flags. */
  qtyChecked: boolean;
  qualityChecked: boolean;
  enclosuresChecked: boolean;
}

export interface Problem {
  id: string;
  message: string;
}

/** Every reason a dispatch is currently blocked. Empty ⇒ ready to ship. */
export function validate(
  lines: PackLine[],
  cartons: Carton[],
  d: DispatchState,
): Problem[] {
  const out: Problem[] = [];

  for (const l of lines) {
    if (l.packed > l.ordered) {
      out.push({ id: `over-${l.id}`, message: `${l.name}：過剰梱包（梱包 ${l.packed} > 受注 ${l.ordered}）。受注数まで戻してください。` });
    }
  }
  const unsettled = lines.filter((l) => !lineSettled(l));
  for (const l of unsettled) {
    if (l.held && l.reason === "") {
      out.push({ id: `reason-${l.id}`, message: `${l.name}：保留理由を選択してください。` });
    } else if (!l.held) {
      out.push({ id: `short-${l.id}`, message: `${l.name}：梱包未完了（${l.packed} / ${l.ordered}）。残りを梱包するか保留にしてください。` });
    }
  }

  if (cartons.length === 0) {
    out.push({ id: "no-carton", message: "カートンが1つもありません。カートンをスキャンして開いてください。" });
  }
  const unweighed = cartons.filter((c) => !c.weight || c.weight <= 0);
  for (const c of unweighed) {
    out.push({ id: `weight-${c.id}`, message: `${c.barcode}：未計量です。重量を入力してください。` });
  }
  const empty = cartons.filter((c) => cartonItemCount(c) === 0);
  for (const c of empty) {
    out.push({ id: `empty-${c.id}`, message: `${c.barcode}：中身が空です。商品を入れるか削除してください。` });
  }

  if (!d.carrier) out.push({ id: "carrier", message: "配送業者を選択してください。" });
  if (!d.tracking.trim()) out.push({ id: "tracking", message: "追跡番号（送り状番号）を入力してください。" });

  if (!d.qtyChecked) out.push({ id: "chk-qty", message: "最終検品：数量一致の確認が未チェックです。" });
  if (!d.qualityChecked) out.push({ id: "chk-quality", message: "最終検品：外装・品質の確認が未チェックです。" });
  if (!d.enclosuresChecked) out.push({ id: "chk-enc", message: "最終検品：同梱物（納品書・請求書）の確認が未チェックです。" });

  return out;
}

export const canDispatch = (lines: PackLine[], cartons: Carton[], d: DispatchState) =>
  validate(lines, cartons, d).length === 0;

// ─── cloning ──────────────────────────────────────────────────────────────────
export function cloneLines(s: Shipment): PackLine[] {
  return s.lines.map((l) => ({ ...l }));
}

// ─── seed data ──────────────────────────────────────────────────────────────────
export const SHIPMENTS: Shipment[] = [
  {
    shipmentNo: "SH-2026-1042",
    orderNo: "SO-2026-0488",
    shipToName: "株式会社みなと商会　物流センター",
    shipToAddr: "〒231-0023 神奈川県横浜市中区山下町2-8",
    shipDate: "2026-06-23",
    service: "宅配便（午前指定）",
    packer: "山田 健一",
    lines: [
      { id: "L1", name: "ステンレスボトル 500ml シルバー", sku: "BTL-500-SV", jan: "4901234500011", ordered: 4, packed: 0, held: false, reason: "" },
      { id: "L2", name: "トラベルポーチ Mサイズ ネイビー", sku: "PCH-M-NV", jan: "4901234500028", ordered: 2, packed: 0, held: false, reason: "" },
      { id: "L3", name: "USB-C ケーブル 1.5m", sku: "CBL-USBC-15", jan: "4901234500035", ordered: 6, packed: 0, held: false, reason: "" },
      { id: "L4", name: "折りたたみ傘 60cm ブラック", sku: "UMB-60-BK", jan: "4901234500042", ordered: 1, packed: 0, held: false, reason: "" },
      { id: "L5", name: "保冷バッグ 10L グレー", sku: "BAG-CL-10", jan: "4901234500059", ordered: 3, packed: 0, held: false, reason: "" },
    ],
  },
  {
    shipmentNo: "SH-2026-1043",
    orderNo: "SO-2026-0491",
    shipToName: "むさし物産　西日本DC",
    shipToAddr: "〒550-0002 大阪府大阪市西区江戸堀1-12",
    shipDate: "2026-06-24",
    service: "宅配便（時間帯おまかせ）",
    packer: "鈴木 美咲",
    lines: [
      { id: "M1", name: "デスクオーガナイザー 木目", sku: "ORG-WD-01", jan: "4901234600017", ordered: 2, packed: 0, held: false, reason: "" },
      { id: "M2", name: "A5 ノート 方眼 5冊パック", sku: "NTB-A5-5P", jan: "4901234600024", ordered: 8, packed: 0, held: false, reason: "" },
      { id: "M3", name: "ボールペン 0.5mm 黒 10本", sku: "PEN-05-BK10", jan: "4901234600031", ordered: 5, packed: 0, held: false, reason: "" },
    ],
  },
];

/** Carton barcodes the demo cartons map to — handy for the scan hint. */
export const SAMPLE_CARTON_BARCODES = ["CT-001", "CT-002", "CT-003"];

"use client";

import * as React from "react";
import {
  IconBarcode,
  IconScan,
  IconSearch,
  IconTruckDelivery,
  IconCalendarEvent,
  IconMapPin,
  IconUser,
  IconClipboardList,
  IconClipboardCheck,
  IconDeviceFloppy,
  IconAlertTriangle,
  IconCircleCheck,
  IconCircleDot,
  IconArrowRight,
  IconBox,
  IconBoxSeam,
  IconPackage,
  IconPackageExport,
  IconWeight,
  IconPrinter,
  IconX,
  IconPlus,
  IconTrashX,
  IconReceipt,
} from "@tabler/icons-react";
import {
  Alert,
  AlertDescription,
  AlertTitle,
  Badge,
  Button,
  Card,
  CardContent,
  CardDescription,
  CardHeader,
  CardTitle,
  Checkbox,
  Delta,
  Dialog,
  DialogContent,
  DialogDescription,
  DialogFooter,
  DialogHeader,
  DialogTitle,
  EditableDataTable,
  Input,
  Label,
  NumberInput,
  Progress,
  RevealSection,
  ScanInput,
  Select,
  Separator,
  Statistic,
  formatNumber,
  type EditableColumn,
  type BadgeProps,
  type ScanResult,
  type ProgressTone,
} from "@gunjo/ui";

import {
  CARRIERS,
  CARRIER_LABEL,
  HOLD_REASON_OPTIONS,
  LINE_STATE_LABEL,
  SHIPMENTS,
  SIZE_CODES,
  SAMPLE_CARTON_BARCODES,
  canDispatch,
  cartonItemCount,
  cloneLines,
  completedLineCount,
  heldLineCount,
  lineRemaining,
  lineSettled,
  lineState,
  lookupShipment,
  matchCartonScan,
  matchItemScan,
  overLineCount,
  settledLineCount,
  totalCartonWeight,
  totalOrdered,
  totalPacked,
  unweighedCartonCount,
  validate,
  type Carton,
  type CarrierCode,
  type DispatchState,
  type HoldReason,
  type LineState,
  type PackLine,
  type Shipment,
  type SizeCode,
} from "./data";

type Phase = "lookup" | "packing" | "done";
/** Two-step scan gate: open a carton, then scan items into it. */
type ScanStage = "carton" | "item";

interface FeedEvent {
  id: number;
  kind: "ok" | "warn" | "error";
  label: string;
  detail: string;
}

const STATE_BADGE_VARIANT: Record<LineState, BadgeProps["variant"]> = {
  pending: "outline",
  partial: "info",
  complete: "success",
  held: "secondary",
  over: "destructive",
};

const STATE_ICON: Record<LineState, React.ReactNode> = {
  pending: <IconCircleDot className="h-3.5 w-3.5" aria-hidden="true" />,
  partial: <IconCircleDot className="h-3.5 w-3.5" aria-hidden="true" />,
  complete: <IconCircleCheck className="h-3.5 w-3.5" aria-hidden="true" />,
  held: <IconAlertTriangle className="h-3.5 w-3.5" aria-hidden="true" />,
  over: <IconAlertTriangle className="h-3.5 w-3.5" aria-hidden="true" />,
};

let cartonSeq = 0;

export default function Shipping() {
  const [phase, setPhase] = React.useState<Phase>("lookup");
  const [shipInput, setShipInput] = React.useState("");
  const [lookupError, setLookupError] = React.useState<string | null>(null);

  const [shipment, setShipment] = React.useState<Shipment | null>(null);
  const [lines, setLines] = React.useState<PackLine[]>([]);
  const [cartons, setCartons] = React.useState<Carton[]>([]);

  // two-step scan gate state
  const [scanStage, setScanStage] = React.useState<ScanStage>("carton");
  const [activeCartonId, setActiveCartonId] = React.useState<string | null>(null);
  const [feed, setFeed] = React.useState<FeedEvent[]>([]);
  const feedSeq = React.useRef(0);

  const [dispatch, setDispatch] = React.useState<DispatchState>({
    carrier: "",
    tracking: "",
    deliverySlot: "",
    qtyChecked: false,
    qualityChecked: false,
    enclosuresChecked: false,
  });

  const [showErrors, setShowErrors] = React.useState(false);
  const [summaryOpen, setSummaryOpen] = React.useState(false);
  const [labelOpen, setLabelOpen] = React.useState(false);
  const [savedAt, setSavedAt] = React.useState<string | null>(null);

  const accepted = phase === "done";
  const activeCarton = cartons.find((c) => c.id === activeCartonId) ?? null;

  // ─── totals / progress ───────────────────────────────────────────────────────
  const ordered = totalOrdered(lines);
  const packed = totalPacked(lines);
  const completeLines = completedLineCount(lines);
  const settledLines = settledLineCount(lines);
  const heldCount = heldLineCount(lines);
  const overCount = overLineCount(lines);
  const cartonWeight = totalCartonWeight(cartons);
  const unweighed = unweighedCartonCount(cartons);
  const pct = ordered ? Math.round((packed / ordered) * 100) : 0;

  const problems = React.useMemo(
    () => validate(lines, cartons, dispatch),
    [lines, cartons, dispatch],
  );
  const problemByLine = React.useMemo(() => {
    const m = new Map<string, string>();
    for (const p of problems) {
      const lid = p.id.split("-").slice(1).join("-");
      if (lines.some((l) => l.id === lid) && !m.has(lid)) m.set(lid, p.message);
    }
    return m;
  }, [problems, lines]);

  const packProgressTone: ProgressTone = overCount > 0 ? "destructive" : pct >= 100 ? "success" : "warning";

  function pushFeed(e: Omit<FeedEvent, "id">) {
    feedSeq.current += 1;
    const id = feedSeq.current;
    setFeed((prev) => [{ ...e, id }, ...prev].slice(0, 8));
  }

  // ─── shipment lookup ───────────────────────────────────────────────────────────
  function resolveShipment(value: string) {
    const found = lookupShipment(value);
    if (!found) {
      setLookupError(
        `「${value}」に一致する出荷が見つかりません。出荷番号（例 SH-2026-1042）か受注番号を確認してください。`,
      );
      return;
    }
    setShipment(found);
    setLines(cloneLines(found));
    setCartons([]);
    setActiveCartonId(null);
    setScanStage("carton");
    setDispatch({
      carrier: "",
      tracking: "",
      deliverySlot: "",
      qtyChecked: false,
      qualityChecked: false,
      enclosuresChecked: false,
    });
    setLookupError(null);
    setShowErrors(false);
    setSavedAt(null);
    setFeed([]);
    setPhase("packing");
  }

  // ─── line / carton mutation ─────────────────────────────────────────────────────
  const patchLine = React.useCallback((id: string, patch: Partial<PackLine>) => {
    setLines((prev) => prev.map((l) => (l.id === id ? { ...l, ...patch } : l)));
  }, []);

  const patchCarton = React.useCallback((id: string, patch: Partial<Carton>) => {
    setCartons((prev) => prev.map((c) => (c.id === id ? { ...c, ...patch } : c)));
  }, []);

  // ─── STEP 1: carton scan (the gate) — open a carton as the active target ────────
  const handleCartonScan = (code: string): ScanResult => {
    const res = matchCartonScan(cartons, code);
    if (res.kind === "existing") {
      setActiveCartonId(res.cartonId);
      setScanStage("item");
      const c = cartons.find((x) => x.id === res.cartonId)!;
      pushFeed({ kind: "ok", label: `カートン ${res.barcode}`, detail: `再オープン（${cartonItemCount(c)} 点）` });
      return { ok: true, message: `カートン ${res.barcode} を開きました。商品をスキャンしてください。` };
    }
    // new carton
    cartonSeq += 1;
    const id = `CT${cartonSeq}-${res.barcode}`;
    const carton: Carton = {
      id,
      barcode: res.barcode,
      size: "80",
      weight: 0,
      contents: {},
      closed: false,
    };
    setCartons((prev) => [...prev, carton]);
    setActiveCartonId(id);
    setScanStage("item");
    pushFeed({ kind: "ok", label: `カートン ${res.barcode}`, detail: "新規オープン" });
    return { ok: true, message: `カートン ${res.barcode} を新規に開きました。商品をスキャンしてください。` };
  };

  // ─── STEP 2: item scan → pack into the active carton, +1 ─────────────────────────
  const handleItemScan = (code: string): ScanResult => {
    if (!activeCarton) {
      return { ok: false, message: "先にカートン（梱包箱）をスキャンして開いてください。" };
    }
    const res = matchItemScan(lines, code);
    if (res.kind === "packed") {
      patchLine(res.lineId, { packed: res.packed });
      patchCarton(activeCarton.id, {
        contents: { ...activeCarton.contents, [res.lineId]: (activeCarton.contents[res.lineId] ?? 0) + 1 },
      });
      pushFeed({ kind: "ok", label: res.name, detail: `→ ${activeCarton.barcode}（${res.packed}/${res.ordered}）` });
      return {
        ok: true,
        message: `${res.name} を ${activeCarton.barcode} に梱包（${res.packed} / ${res.ordered} 点）。`,
      };
    }
    if (res.kind === "full") {
      pushFeed({ kind: "warn", label: res.name, detail: "受注数に到達済み" });
      return { ok: false, message: `${res.name} は受注数 ${res.ordered} 点に達しています。過剰梱包になるため加算しません。` };
    }
    if (res.kind === "held") {
      pushFeed({ kind: "warn", label: res.name, detail: "保留中の明細" });
      return { ok: false, message: `${res.name} は保留中です。保留を解除してから梱包してください。` };
    }
    pushFeed({ kind: "error", label: res.code, detail: "受注に無い商品" });
    return { ok: false, message: `受注に無い商品です（コード ${res.code}）。出荷明細を確認してください。` };
  };

  function closeActiveCarton() {
    if (activeCarton) patchCarton(activeCarton.id, { closed: true });
    setActiveCartonId(null);
    setScanStage("carton");
  }

  function removeCarton(id: string) {
    const c = cartons.find((x) => x.id === id);
    if (!c) return;
    // return its contents to the unpacked pool
    setLines((prev) =>
      prev.map((l) => {
        const n = c.contents[l.id] ?? 0;
        return n ? { ...l, packed: Math.max(0, l.packed - n) } : l;
      }),
    );
    setCartons((prev) => prev.filter((x) => x.id !== id));
    if (activeCartonId === id) {
      setActiveCartonId(null);
      setScanStage("carton");
    }
    pushFeed({ kind: "warn", label: `カートン ${c.barcode}`, detail: "削除（中身を戻しました）" });
  }

  // ─── hold toggle ────────────────────────────────────────────────────────────────
  function toggleHold(id: string, next: boolean) {
    patchLine(id, next ? { held: true } : { held: false, reason: "" });
  }

  // ─── dispatch ───────────────────────────────────────────────────────────────────
  function attemptDispatch() {
    if (!canDispatch(lines, cartons, dispatch)) {
      setShowErrors(true);
      return;
    }
    setShowErrors(false);
    setPhase("done");
    setSummaryOpen(false);
  }

  function reset() {
    setPhase("lookup");
    setShipment(null);
    setLines([]);
    setCartons([]);
    setShipInput("");
    setActiveCartonId(null);
    setScanStage("carton");
    setFeed([]);
    setShowErrors(false);
    setSavedAt(null);
    setDispatch({
      carrier: "",
      tracking: "",
      deliverySlot: "",
      qtyChecked: false,
      qualityChecked: false,
      enclosuresChecked: false,
    });
  }

  // ─── pack-lines grid columns ─────────────────────────────────────────────────────
  const columns: EditableColumn<PackLine>[] = [
    {
      id: "name",
      header: "商品 / SKU・JAN",
      minWidth: "13rem",
      cell: (row) => (
        <div className="flex flex-col">
          <span className="font-medium leading-snug">{row.name}</span>
          <span className="font-mono text-xs text-muted-foreground tabular-nums">
            {row.sku} · {row.jan}
          </span>
        </div>
      ),
    },
    {
      id: "ordered",
      header: "受注数量",
      align: "center",
      width: "5.5rem",
      cell: (row) => <span className="tabular-nums">{formatNumber(row.ordered)}</span>,
    },
    {
      id: "packed",
      header: "梱包済数量",
      align: "center",
      width: "9rem",
      minWidth: "8.5rem",
      cell: (row, ctx) => (
        <NumberInput
          layout="stepper"
          value={row.packed}
          min={0}
          max={row.ordered}
          onValueChange={(n) => patchLine(row.id, { packed: n })}
          aria-label={`${ctx.ariaLabel}（スキャンで加算・手修正可）`}
          aria-invalid={row.packed > row.ordered ? true : undefined}
          disabled={accepted || row.held}
        />
      ),
    },
    {
      id: "remaining",
      header: "残数",
      align: "center",
      width: "7rem",
      minWidth: "6rem",
      cell: (row) => {
        if (row.held) return <span className="text-xs font-medium text-muted-foreground">保留</span>;
        const rem = lineRemaining(row); // >0 残, 0 完了, <0 過剰
        // meaning carried by text label + sign, never colour alone.
        return (
          <Delta
            value={-rem}
            format={(n) => (n === 0 ? "0" : formatNumber(Math.abs(n)))}
            hideArrow
            labels={{ positive: "過剰", negative: "残", zero: "完了" }}
            showLabel
            tones={{ positive: "warning", negative: "muted", zero: "success" }}
          />
        );
      },
    },
    {
      id: "cartons",
      header: "割当カートン",
      minWidth: "8rem",
      cell: (row) => {
        const inCartons = cartons.filter((c) => (c.contents[row.id] ?? 0) > 0);
        if (inCartons.length === 0)
          return <span className="text-xs text-muted-foreground">—</span>;
        return (
          <div className="flex flex-wrap gap-1">
            {inCartons.map((c) => (
              <Badge key={c.id} variant="outline" className="gap-1 font-mono">
                <IconBox className="h-3 w-3" aria-hidden="true" />
                {c.barcode}×{c.contents[row.id]}
              </Badge>
            ))}
          </div>
        );
      },
    },
    {
      id: "state",
      header: "状態",
      align: "center",
      width: "6rem",
      cell: (row) => {
        const s = lineState(row);
        return (
          <Badge variant={STATE_BADGE_VARIANT[s]} className="gap-1">
            {STATE_ICON[s]}
            {LINE_STATE_LABEL[s]}
          </Badge>
        );
      },
    },
    {
      id: "hold",
      header: "保留 / 欠品",
      minWidth: "13rem",
      cell: (row, ctx) => {
        const reasonMissing = row.held && row.reason === "";
        return (
          <div className="flex flex-col gap-2">
            <Checkbox
              checked={row.held}
              onCheckedChange={(v) => toggleHold(row.id, v)}
              disabled={accepted}
              label="保留にする"
            />
            {row.held ? (
              <Select
                value={row.reason}
                onChange={(e) => patchLine(row.id, { reason: e.target.value as HoldReason | "" })}
                aria-label={`${ctx.ariaLabel}（保留理由）`}
                aria-invalid={showErrors && reasonMissing ? true : undefined}
                disabled={accepted}
                className="h-8"
              >
                <option value="">保留理由を選択</option>
                {HOLD_REASON_OPTIONS.map((o) => (
                  <option key={o.value} value={o.value}>
                    {o.label}
                  </option>
                ))}
              </Select>
            ) : (
              <span className="text-xs text-muted-foreground">残りをカートンへスキャン</span>
            )}
          </div>
        );
      },
    },
  ];

  function footerCell(col: EditableColumn<PackLine>) {
    if (col.id === "name") return <span className="font-semibold">合計</span>;
    if (col.id === "ordered")
      return <span className="font-semibold tabular-nums">{formatNumber(ordered)}</span>;
    if (col.id === "packed")
      return <span className="font-semibold tabular-nums">{formatNumber(packed)}</span>;
    if (col.id === "state")
      return (
        <span className="text-xs font-medium text-muted-foreground tabular-nums">
          完了 {completeLines}/{lines.length} 行
        </span>
      );
    if (col.id === "hold")
      return (
        <span className="text-xs font-medium text-muted-foreground tabular-nums">
          保留 {heldCount} 件
        </span>
      );
    return null;
  }

  const statusBadge = accepted ? (
    <Badge variant="success" className="h-6 gap-1">
      <IconCircleCheck className="h-3.5 w-3.5" aria-hidden="true" />
      出荷済
    </Badge>
  ) : packed === 0 && cartons.length === 0 ? (
    <Badge variant="outline" className="h-6">
      未検品
