            </div>

            <Separator />
            <div className="flex flex-col gap-2">
              <p className="text-xs font-medium text-muted-foreground">本日の梱包待ち</p>
              <ul className="flex flex-col gap-2">
                {SHIPMENTS.map((s) => (
                  <li key={s.shipmentNo}>
