                      <span className="flex flex-col">
                        <span className="font-mono text-sm font-medium">{s.shipmentNo}</span>
                        <span className="text-xs text-muted-foreground">
                          {s.shipToName} · {s.lines.length} 明細 · {s.service}
                        </span>
                      </span>
                      <Badge variant="outline" className="shrink-0">
                        出荷予定 {s.shipDate}
                      </Badge>
                    </button>
                  </li>
                ))}
              </ul>
            </div>
          </CardContent>
        </Card>
      ) : null}

      {/* ─── packing / done ─── */}
      {shipment ? (
        <>
          {/* shipment header */}
          <Card>
            <CardHeader className="pb-4">
