                <div className="flex flex-col gap-1">
                  <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                    <IconTruckDelivery className="h-5 w-5" aria-hidden="true" />
                    <span className="font-mono">{shipment.shipmentNo}</span>
                  </CardTitle>
                  <CardDescription>
                    受注 {shipment.orderNo} · {shipment.shipToName}
                  </CardDescription>
                </div>
                {statusBadge}
              </div>
            </CardHeader>
            <CardContent>
              <dl className="grid grid-cols-2 gap-x-4 gap-y-3 text-sm sm:grid-cols-3 lg:grid-cols-6">
                <div className="flex flex-col">
                  <dt className="flex items-center gap-1 text-xs text-muted-foreground">
                    <IconCalendarEvent className="h-3.5 w-3.5" aria-hidden="true" />
                    出荷予定日
                  </dt>
                  <dd className="tabular-nums">{shipment.shipDate}</dd>
                </div>
                <div className="flex flex-col sm:col-span-2">
                  <dt className="flex items-center gap-1 text-xs text-muted-foreground">
                    <IconMapPin className="h-3.5 w-3.5" aria-hidden="true" />
                    配送先
                  </dt>
                  <dd>
                    {shipment.shipToName}
                    <span className="block text-xs text-muted-foreground">{shipment.shipToAddr}</span>
                  </dd>
                </div>
                <div className="flex flex-col">
                  <dt className="text-xs text-muted-foreground">配送便</dt>
                  <dd>{shipment.service}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="flex items-center gap-1 text-xs text-muted-foreground">
                    <IconUser className="h-3.5 w-3.5" aria-hidden="true" />
                    担当者
                  </dt>
                  <dd>{shipment.packer}</dd>
                </div>
                <div className="flex flex-col">
                  <dt className="text-xs text-muted-foreground">明細行数</dt>
                  <dd className="tabular-nums">{shipment.lines.length} 行</dd>
                </div>
              </dl>
            </CardContent>
          </Card>

          {/* flow stepper */}
          <Card>
            <CardContent className="pt-6">
              <FlowStepper packed={packed} settled={settledLines >= lines.length && lines.length > 0} weighed={cartons.length > 0 && unweighed === 0} accepted={accepted} hasCartons={cartons.length > 0} carrierSet={!!dispatch.carrier} />
            </CardContent>
          </Card>

          {/* progress */}
          <Card>
            <CardHeader className="pb-3">
              <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                <IconClipboardList className="h-5 w-5" aria-hidden="true" />
                梱包進捗
              </CardTitle>
            </CardHeader>
            <CardContent className="flex flex-col gap-4">
              <div className="grid grid-cols-2 gap-3 sm:grid-cols-4">
                <Statistic
                  label="梱包点数"
                  value={`${formatNumber(packed)} / ${formatNumber(ordered)} 点`}
                  hint={`達成 ${pct}%`}
                />
                <Statistic
                  label="完了行"
                  value={`${completeLines} / ${lines.length} 行`}
                  hint={`保留 ${heldCount} 件`}
                />
                <Statistic
                  label="カートン"
                  value={`${formatNumber(cartons.length)} 箱`}
                  trend={unweighed > 0 ? "down" : "flat"}
                  tone={unweighed > 0 ? "negative" : "neutral"}
                  change={unweighed > 0 ? `未計量 ${unweighed}` : "計量済"}
                />
                <Statistic
                  label="総重量"
                  value={`${cartonWeight.toFixed(1)} kg`}
                  hint={overCount > 0 ? `過剰梱包 ${overCount} 件` : "過不足なし"}
