              </div>
              <div className="flex flex-col gap-1.5">
                <div className="flex items-center justify-between text-xs font-medium text-muted-foreground">
                  <span>梱包全体の進捗</span>
                  <span className="tabular-nums">
                    {formatNumber(packed)} / {formatNumber(ordered)} 点（{pct}%）
                  </span>
                </div>
                <Progress
                  value={packed}
                  max={ordered || 1}
                  tone={packProgressTone}
                  label="梱包全体の進捗"
                  valueText={`梱包 ${packed} / ${ordered} 点（${pct}%）${overCount > 0 ? "・過剰あり" : ""}`}
                />
              </div>
            </CardContent>
          </Card>

          {/* two-step scan — the centerpiece */}
          {!accepted ? (
            <Card>
              <CardHeader className="pb-3">
                <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                  <IconScan className="h-5 w-5" aria-hidden="true" />
                  2段スキャン（カートン → 商品）
                </CardTitle>
                <CardDescription>
                  ① カートン（梱包箱）のバーコードをスキャンして開く → ② 商品の JAN/SKU
                  をスキャンすると、開いているカートンに梱包され梱包済数量が 1 点ずつ加算されます。
                </CardDescription>
              </CardHeader>
              <CardContent className="flex flex-col gap-4">
                {/* stage indicator */}
                <ol className="flex items-center gap-2 text-sm" aria-label="スキャン手順">
                  <li
                    className={
                      scanStage === "carton"
                        ? "flex items-center gap-1.5 font-semibold text-primary"
                        : "flex items-center gap-1.5 text-success-strong"
                    }
                  >
                    {activeCarton ? (
                      <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
                    ) : (
                      <IconCircleDot className="h-4 w-4" aria-hidden="true" />
                    )}
                    ① カートン
                  </li>
                  <IconArrowRight className="h-4 w-4 text-muted-foreground" aria-hidden="true" />
                  <li
                    className={
                      scanStage === "item"
                        ? "flex items-center gap-1.5 font-semibold text-primary"
                        : "flex items-center gap-1.5 text-muted-foreground"
                    }
                  >
                    <IconCircleDot className="h-4 w-4" aria-hidden="true" />② 商品
                  </li>
                </ol>

                {/* STEP 1 — carton scan */}
                {scanStage === "carton" ? (
                  <ScanInput
                    key="carton-scan"
                    label="① カートンをスキャン"
                    description={`梱包箱のバーコードをスキャン（または入力して Enter）。新しい番号なら新規カートンとして開きます（例 ${SAMPLE_CARTON_BARCODES.join(" / ")}）。`}
                    placeholder="カートンをスキャン…（例 CT-001）"
                    icon={<IconBox className="h-4 w-4" aria-hidden="true" />}
                    inputMode="text"
                    onScan={handleCartonScan}
                    autoFocus
                  />
                ) : (
                  /* STEP 2 — item scan (only after a carton is open) */
                  <div className="flex flex-col gap-2">
                    <Alert variant="success">
                      <IconBoxSeam className="h-4 w-4" aria-hidden="true" />
                      <AlertTitle as="h3">
                        カートン {activeCarton?.barcode} を梱包中（{activeCarton ? cartonItemCount(activeCarton) : 0} 点）
                      </AlertTitle>
                      <AlertDescription>
                        この商品をスキャンするとこのカートンに梱包されます。別の箱へ移る場合は「カートンを閉じる」。
                      </AlertDescription>
                    </Alert>
                    <ScanInput
                      key={`item-${activeCarton?.id}`}
                      label="② 商品をスキャン"
                      description="商品の JAN / SKU をスキャン（または入力して Enter）すると、このカートンに 1 点梱包されます。"
                      placeholder="商品をスキャン…（例 4901234500011）"
