                    />
                    <div className="flex flex-wrap gap-2">
                      <Button variant="outline" size="sm" onClick={closeActiveCarton}>
                        <IconBox className="h-4 w-4" aria-hidden="true" />
                        カートンを閉じる
                      </Button>
                      <Button
                        variant="ghost"
                        size="sm"
                        onClick={() => {
                          setScanStage("carton");
                          setActiveCartonId(null);
                        }}
                      >
                        <IconBarcode className="h-4 w-4" aria-hidden="true" />
                        別のカートンを開く
                      </Button>
                    </div>
                  </div>
                )}

                {/* recent scan feed */}
                {feed.length ? (
                  <div className="flex flex-col gap-1.5">
                    <p className="text-xs font-medium text-muted-foreground">最近のスキャン</p>
                    <ul className="flex flex-col gap-1">
                      {feed.map((f) => (
                        <li
                          key={f.id}
                          className="flex items-center justify-between gap-2 rounded-md border bg-muted/30 px-2.5 py-1.5 text-xs"
                        >
                          <span className="flex items-center gap-2 truncate">
                            <Badge
                              variant={f.kind === "ok" ? "success" : f.kind === "warn" ? "warning" : "destructive"}
