            </CardHeader>
            <CardContent>
              <EditableDataTable
                columns={columns}
                rows={lines}
                getRowId={(l) => l.id}
                rowLabel={(i) => lines[i]?.name ?? `行 ${i + 1}`}
                getRowError={showErrors ? (row) => problemByLine.get(row.id) : undefined}
                renderFooterCell={footerCell}
                caption="検品・梱包明細 — スキャンで梱包済が加算され、残数・状態・割当カートンが自動更新されます。"
              />
            </CardContent>
