            <CardContent className="flex flex-col gap-3">
              {cartons.length === 0 ? (
                <div className="rounded-md border border-dashed p-6 text-center text-sm text-muted-foreground">
                  <IconPackage className="mx-auto mb-2 h-6 w-6" aria-hidden="true" />
                  まだカートンがありません。上のスキャン欄でカートンをスキャンして開いてください。
                </div>
              ) : (
                cartons.map((c) => {
                  const count = cartonItemCount(c);
                  const isActive = c.id === activeCartonId;
                  const noWeight = !c.weight || c.weight <= 0;
                  // fill bar: heuristic capacity by size code, just to show Progress tone in action
                  const cap = { "60": 8, "80": 14, "100": 20, "120": 30, "140": 40, "160": 50 }[c.size];
                  const fillPct = Math.round((count / cap) * 100);
                  const fillTone: ProgressTone = fillPct >= 100 ? "destructive" : fillPct >= 80 ? "warning" : "info";
                  return (
                    <div
                      key={c.id}
                      className={
                        isActive
                          ? "rounded-lg border-2 border-primary bg-muted/30 p-3"
                          : "rounded-lg border p-3"
                      }
                    >
                      <div className="flex flex-wrap items-center justify-between gap-2">
                        <div className="flex items-center gap-2">
                          <IconBox className="h-4 w-4 text-muted-foreground" aria-hidden="true" />
                          <span className="font-mono text-sm font-semibold">{c.barcode}</span>
                          {isActive ? (
                            <Badge variant="info" className="gap-1">
                              <IconCircleDot className="h-3 w-3" aria-hidden="true" />
                              梱包中
                            </Badge>
                          ) : c.closed ? (
                            <Badge variant="success" className="gap-1">
                              <IconCircleCheck className="h-3 w-3" aria-hidden="true" />
                              閉じ済
                            </Badge>
                          ) : null}
                          {noWeight ? (
                            <Badge variant="warning" className="gap-1">
                              <IconWeight className="h-3 w-3" aria-hidden="true" />
                              未計量
                            </Badge>
                          ) : null}
                        </div>
                        {!accepted ? (
                          <Button
                            variant="ghost"
                            size="icon"
                            className="h-8 w-8"
                            aria-label={`カートン ${c.barcode} を削除`}
                            onClick={() => removeCarton(c.id)}
                          >
                            <IconTrashX className="h-4 w-4" />
                          </Button>
                        ) : null}
                      </div>

                      {/* contents */}
                      <ul className="mt-2 flex flex-col gap-1 text-sm">
                        {count === 0 ? (
                          <li className="text-xs text-muted-foreground">（空のカートン）</li>
                        ) : (
                          Object.entries(c.contents)
                            .filter(([, n]) => n > 0)
                            .map(([lid, n]) => {
                              const line = lines.find((l) => l.id === lid);
                              return (
                                <li key={lid} className="flex items-center justify-between gap-2">
                                  <span className="truncate">{line?.name ?? lid}</span>
                                  <span className="shrink-0 font-mono tabular-nums text-muted-foreground">×{n}</span>
                                </li>
                              );
                            })
                        )}
                      </ul>

                      {/* fill bar (Progress tone) */}
                      <div className="mt-2 flex flex-col gap-1">
                        <div className="flex items-center justify-between text-xs text-muted-foreground">
                          <span className="flex items-center gap-1">
                            <IconPackage className="h-3.5 w-3.5" aria-hidden="true" />
                            積載 {count} / 目安 {cap} 点
                          </span>
                          <span className="tabular-nums">{fillPct}%</span>
                        </div>
                        <Progress
                          value={count}
                          max={cap}
                          tone={fillTone}
                          className="h-2"
                          label={`カートン ${c.barcode} の積載`}
                          valueText={`積載 ${count} / 目安 ${cap} 点（${fillPct}%）`}
                        />
                      </div>

                      {/* size + weight controls */}
                      <div className="mt-3 grid grid-cols-1 gap-3 sm:grid-cols-2">
                        <div className="flex flex-col gap-1">
                          <Label htmlFor={`size-${c.id}`} className="text-xs">サイズ（規格）</Label>
                          <Select
                            id={`size-${c.id}`}
                            value={c.size}
                            onChange={(e) => patchCarton(c.id, { size: e.target.value as SizeCode })}
                            disabled={accepted}
                            className="h-9"
                          >
                            {SIZE_CODES.map((s) => (
                              <option key={s} value={s}>
                                {s} サイズ
                              </option>
                            ))}
                          </Select>
                        </div>
                        <div className="flex flex-col gap-1">
                          <Label htmlFor={`weight-${c.id}`} className="flex items-center gap-1 text-xs">
                            <IconWeight className="h-3.5 w-3.5" aria-hidden="true" />
                            重量（kg）
                          </Label>
                          <div className="flex items-center gap-2">
                            <NumberInput
                              id={`weight-${c.id}`}
                              value={c.weight || undefined}
                              min={0}
                              step={0.1}
                              onValueChange={(n) => patchCarton(c.id, { weight: n })}
                              aria-label={`カートン ${c.barcode} の重量（kg）`}
                              aria-invalid={showErrors && noWeight ? true : undefined}
                              disabled={accepted}
                              placeholder="0.0"
                              className="w-28"
                            />
                            <span className="text-sm text-muted-foreground">kg</span>
                          </div>
                        </div>
                      </div>
                    </div>
                  );
                })
              )}
            </CardContent>
          </Card>

          {/* final inspection checklist */}
          <RevealSection open={!accepted && (packed > 0 || cartons.length > 0)} label="最終検品チェックリスト">
            <Card>
              <CardHeader className="pb-3">
                <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                  <IconClipboardCheck className="h-5 w-5" aria-hidden="true" />
                  最終検品
                </CardTitle>
                <CardDescription>
                  出荷確定の前に、数量一致・外装/品質・同梱物を確認してチェックを入れてください。
                </CardDescription>
              </CardHeader>
              <CardContent className="flex flex-col gap-3">
                <Checkbox
                  checked={dispatch.qtyChecked}
                  onCheckedChange={(v) => setDispatch((d) => ({ ...d, qtyChecked: v }))}
                  label="数量一致を確認"
                  description={`梱包 ${packed} / 受注 ${ordered} 点${settledLines >= lines.length ? "・全行が梱包完了または保留済み" : "・未完了の行があります"}`}
                />
                <Checkbox
                  checked={dispatch.qualityChecked}
                  onCheckedChange={(v) => setDispatch((d) => ({ ...d, qualityChecked: v }))}
                  label="外装・品質を確認"
                  description="破損・汚れ・誤梱包がないこと、カートンが封緘されていることを確認"
                />
                <Checkbox
                  checked={dispatch.enclosuresChecked}
                  onCheckedChange={(v) => setDispatch((d) => ({ ...d, enclosuresChecked: v }))}
                  label="同梱物を確認（納品書・請求書）"
                  description="納品書・請求書など必要書類を同梱したこと"
                />
              </CardContent>
            </Card>
          </RevealSection>

          {/* carrier + tracking */}
          {!accepted ? (
            <Card>
              <CardHeader className="pb-3">
                <CardTitle as="h2" className="flex items-center gap-2 text-lg">
                  <IconReceipt className="h-5 w-5" aria-hidden="true" />
                  配送ラベル / 送り状
                </CardTitle>
                <CardDescription>配送業者・追跡番号・お届け希望日時を入力します。</CardDescription>
              </CardHeader>
              <CardContent className="grid grid-cols-1 gap-4 sm:grid-cols-3">
                <Select
                  label="配送業者"
                  value={dispatch.carrier}
                  onChange={(e) => setDispatch((d) => ({ ...d, carrier: e.target.value as CarrierCode | "" }))}
                  aria-invalid={showErrors && !dispatch.carrier ? true : undefined}
                >
                  <option value="">選択してください</option>
                  {CARRIERS.map((c) => (
                    <option key={c.code} value={c.code}>
                      {c.label}
                    </option>
                  ))}
                </Select>
                <div className="flex flex-col gap-1.5">
                  <Label htmlFor="tracking">追跡番号（送り状番号）</Label>
                  <Input
                    id="tracking"
                    value={dispatch.tracking}
                    onChange={(e) => setDispatch((d) => ({ ...d, tracking: e.target.value }))}
                    placeholder={
                      dispatch.carrier ? CARRIERS.find((c) => c.code === dispatch.carrier)?.hint : "配送業者を選択"
                    }
                    inputMode="numeric"
                    autoComplete="off"
                    aria-invalid={showErrors && !dispatch.tracking.trim() ? true : undefined}
                  />
                </div>
                <div className="flex flex-col gap-1.5">
                  <Label htmlFor="slot">お届け希望日時</Label>
                  <Select
                    id="slot"
                    value={dispatch.deliverySlot}
                    onChange={(e) => setDispatch((d) => ({ ...d, deliverySlot: e.target.value }))}
                  >
                    <option value="">指定なし</option>
                    <option value="am">午前中</option>
                    <option value="12-14">12-14時</option>
                    <option value="14-16">14-16時</option>
                    <option value="16-18">16-18時</option>
                    <option value="18-20">18-20時</option>
                    <option value="19-21">19-21時</option>
                  </Select>
                </div>
              </CardContent>
            </Card>
          ) : null}

          {/* validation summary on dispatch attempt */}
          <RevealSection open={showErrors && problems.length > 0} label="出荷確定エラー">
            <Alert variant="destructive">
              <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h2">出荷を確定できません（{problems.length} 件）</AlertTitle>
              <AlertDescription>
                <ul className="ml-4 list-disc">
                  {problems.map((p) => (
                    <li key={p.id}>{p.message}</li>
                  ))}
                </ul>
              </AlertDescription>
            </Alert>
          </RevealSection>

          {/* over-pack warning */}
          <RevealSection open={!accepted && overCount > 0} label="過剰梱包の警告">
            <Alert variant="warning">
              <IconAlertTriangle className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h2">過剰梱包があります（{overCount} 件）</AlertTitle>
              <AlertDescription>
                受注数量を超えて梱包された行があります。梱包済数量を受注数まで戻してください。
              </AlertDescription>
            </Alert>
          </RevealSection>

          {/* dispatch confirmation */}
          {accepted ? (
            <Alert variant="success">
              <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
              <AlertTitle as="h2">出荷確定済み</AlertTitle>
              <AlertDescription>
                {shipment.shipmentNo}（{shipment.shipToName}）を出荷しました。
                {cartons.length} 箱 · 合計 {cartonWeight.toFixed(1)} kg ·{" "}
                {dispatch.carrier ? CARRIER_LABEL[dispatch.carrier] : ""} 追跡 {dispatch.tracking}。
              </AlertDescription>
            </Alert>
          ) : null}

          {/* actions */}
          <div className="flex flex-col gap-2 sm:flex-row sm:items-center sm:justify-between">
            <div className="text-xs text-muted-foreground" aria-live="polite">
              {accepted
                ? "この出荷は確定済みです（読み取り専用）。"
                : savedAt
                  ? `一時保存しました（${savedAt}）。`
                  : `梱包 ${formatNumber(packed)} / ${formatNumber(ordered)} 点 · ${cartons.length} 箱 · ${cartonWeight.toFixed(1)} kg · 残ブロック ${problems.length} 件`}
            </div>
            <div className="flex flex-wrap items-center gap-2">
              {accepted ? (
                <>
                  <Button variant="outline" onClick={() => setSummaryOpen(true)}>
                    <IconClipboardList className="h-4 w-4" aria-hidden="true" />
                    出荷サマリ
                  </Button>
                  <Button variant="secondary" onClick={reset}>
                    次の出荷を梱包
                  </Button>
                </>
              ) : (
                <>
                  <Button
                    variant="ghost"
                    onClick={() =>
                      setSavedAt(
                        new Date().toLocaleTimeString("ja-JP", { hour: "2-digit", minute: "2-digit" }),
                      )
                    }
                  >
                    <IconDeviceFloppy className="h-4 w-4" aria-hidden="true" />
                    一時保存
                  </Button>
                  <Button variant="outline" onClick={() => setLabelOpen(true)} disabled={!dispatch.carrier || !dispatch.tracking.trim()}>
                    <IconPrinter className="h-4 w-4" aria-hidden="true" />
                    ラベル印刷
                  </Button>
                  <Button variant="outline" onClick={() => setSummaryOpen(true)}>
                    <IconClipboardList className="h-4 w-4" aria-hidden="true" />
                    出荷サマリ
                  </Button>
                  <Button variant="success" onClick={attemptDispatch}>
                    <IconPackageExport className="h-4 w-4" aria-hidden="true" />
                    出荷確定
                  </Button>
                </>
              )}
            </div>
          </div>
        </>
      ) : null}

      {/* summary dialog */}
      <Dialog open={summaryOpen} onOpenChange={setSummaryOpen}>
        <DialogContent className="max-h-[85vh] overflow-y-auto sm:max-w-lg">
          <DialogHeader>
            <DialogTitle>出荷サマリ — {shipment?.shipmentNo}</DialogTitle>
            <DialogDescription>
              {shipment?.shipToName} · 出荷予定 {shipment?.shipDate}
            </DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-3 text-sm">
            <div className="flex flex-col gap-2">
              <p className="text-xs font-medium text-muted-foreground">カートン × 重量</p>
              <ul className="flex flex-col divide-y">
                {cartons.length === 0 ? (
                  <li className="py-2 text-muted-foreground">カートンなし</li>
                ) : (
                  cartons.map((c) => (
                    <li key={c.id} className="flex items-center justify-between gap-3 py-2">
                      <span className="flex flex-col">
                        <span className="font-mono font-medium">{c.barcode}</span>
                        <span className="text-xs text-muted-foreground">
                          {c.size} サイズ · {cartonItemCount(c)} 点
                        </span>
                      </span>
                      <span className="shrink-0 tabular-nums">
                        {c.weight ? `${c.weight.toFixed(1)} kg` : "未計量"}
                      </span>
                    </li>
                  ))
                )}
              </ul>
            </div>
            <Separator />
            <dl className="flex flex-col gap-1.5">
              <div className="flex justify-between">
                <dt className="text-muted-foreground">梱包点数</dt>
                <dd className="tabular-nums">{formatNumber(packed)} / {formatNumber(ordered)} 点</dd>
              </div>
              <div className="flex justify-between">
                <dt className="text-muted-foreground">カートン数</dt>
                <dd className="tabular-nums">{cartons.length} 箱</dd>
              </div>
              <div className="flex justify-between">
                <dt className="text-muted-foreground">総重量</dt>
                <dd className="tabular-nums">{cartonWeight.toFixed(1)} kg</dd>
              </div>
              <div className="flex justify-between">
                <dt className="text-muted-foreground">保留</dt>
                <dd className="tabular-nums">{heldCount} 件</dd>
              </div>
              <div className="flex justify-between font-semibold">
                <dt>配送業者 / 追跡番号</dt>
                <dd className="text-right">
                  {dispatch.carrier ? CARRIER_LABEL[dispatch.carrier] : "未選択"}
                  <span className="block font-mono text-xs">{dispatch.tracking || "—"}</span>
                </dd>
              </div>
            </dl>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setSummaryOpen(false)}>
              <IconX className="h-4 w-4" aria-hidden="true" />
              閉じる
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>

      {/* label preview dialog */}
      <Dialog open={labelOpen} onOpenChange={setLabelOpen}>
        <DialogContent className="sm:max-w-md">
          <DialogHeader>
            <DialogTitle>送り状プレビュー</DialogTitle>
            <DialogDescription>{shipment?.shipmentNo} の配送ラベル</DialogDescription>
          </DialogHeader>
          <div className="flex flex-col gap-3 rounded-lg border bg-muted/30 p-4 text-sm">
            <div className="flex items-center justify-between">
              <span className="text-xs text-muted-foreground">配送業者</span>
              <span className="font-medium">{dispatch.carrier ? CARRIER_LABEL[dispatch.carrier] : "—"}</span>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-xs text-muted-foreground">追跡番号</span>
              <span className="font-mono">{dispatch.tracking || "—"}</span>
            </div>
            <Separator />
            <div className="flex flex-col">
              <span className="text-xs text-muted-foreground">お届け先</span>
              <span className="font-medium">{shipment?.shipToName}</span>
              <span className="text-xs text-muted-foreground">{shipment?.shipToAddr}</span>
            </div>
            <div className="flex items-center justify-between">
              <span className="text-xs text-muted-foreground">個口数 / 総重量</span>
              <span className="tabular-nums">{cartons.length} 個口 · {cartonWeight.toFixed(1)} kg</span>
            </div>
            <div className="flex items-center justify-center rounded border border-dashed bg-background py-3" aria-hidden="true">
              <IconBarcode className="h-8 w-24" />
            </div>
          </div>
          <DialogFooter>
            <Button variant="outline" onClick={() => setLabelOpen(false)}>
              閉じる
            </Button>
            <Button variant="primary" onClick={() => setLabelOpen(false)}>
              <IconPrinter className="h-4 w-4" aria-hidden="true" />
              印刷
            </Button>
          </DialogFooter>
        </DialogContent>
      </Dialog>
    </main>
  );
}

// ─── flow stepper (inspect → pack → weigh/label → dispatch) ──────────────────────
function FlowStepper({
  packed,
  settled,
  weighed,
  carrierSet,
  accepted,
  hasCartons,
}: {
  packed: number;
  settled: boolean;
  weighed: boolean;
  carrierSet: boolean;
  accepted: boolean;
  hasCartons: boolean;
}) {
  const steps: { label: string; done: boolean; current: boolean }[] = [
    { label: "検品・梱包", done: settled && hasCartons, current: !(settled && hasCartons) },
    { label: "計量・封緘", done: weighed && settled, current: settled && hasCartons && !(weighed && settled) },
    { label: "送り状", done: carrierSet, current: weighed && settled && !carrierSet },
    { label: "出荷確定", done: accepted, current: carrierSet && weighed && settled && !accepted },
  ];
  return (
    <ol className="flex items-center gap-1 overflow-x-auto" aria-label="出荷フロー">
      {steps.map((s, i) => (
        <React.Fragment key={s.label}>
          <li
            className={
              s.done
                ? "flex shrink-0 items-center gap-1.5 text-success-strong"
                : s.current
                  ? "flex shrink-0 items-center gap-1.5 font-semibold text-primary"
                  : "flex shrink-0 items-center gap-1.5 text-muted-foreground"
            }
            aria-current={s.current ? "step" : undefined}
          >
            {s.done ? (
              <IconCircleCheck className="h-4 w-4" aria-hidden="true" />
            ) : (
              <span className="flex h-4 w-4 items-center justify-center rounded-full border text-[10px]">{i + 1}</span>
            )}
            <span className="text-xs sm:text-sm">{s.label}</span>
          </li>
          {i < steps.length - 1 ? (
            <IconArrowRight className="h-3.5 w-3.5 shrink-0 text-muted-foreground" aria-hidden="true" />
          ) : null}
        </React.Fragment>
      ))}
    </ol>
  );
}
